import azure.functions as func
import logging
import json
import hashlib
import re
from datetime import datetime
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.messaging import CloudEvent
from typing import Dict, Any
import os

app = func.FunctionApp()

# Configuration with validation
STORAGE_ACCOUNT_URL = os.environ.get('STORAGE_ACCOUNT_URL', '')
COSMOS_ENDPOINT = os.environ.get('COSMOS_ENDPOINT', '')
COSMOS_DATABASE = os.environ.get('COSMOS_DATABASE', '')
COSMOS_CONTAINER = os.environ.get('COSMOS_CONTAINER', '')
EVENT_GRID_ENDPOINT = os.environ.get('EVENT_GRID_ENDPOINT', '')
ALLOWED_CONTAINERS = os.environ.get('ALLOWED_CONTAINERS', '').split(',')
MAX_FILE_SIZE_MB = int(os.environ.get('MAX_FILE_SIZE_MB', '10'))
ALLOWED_FILE_EXTENSIONS = {'.txt', '.json', '.csv', '.xml'}

# Initialize clients with Managed Identity
credential = DefaultAzureCredential()

def validate_config():
    """Validate required configuration is present"""
    required_configs = {
        'STORAGE_ACCOUNT_URL': STORAGE_ACCOUNT_URL,
        'COSMOS_ENDPOINT': COSMOS_ENDPOINT,
        'COSMOS_DATABASE': COSMOS_DATABASE,
        'COSMOS_CONTAINER': COSMOS_CONTAINER,
        'EVENT_GRID_ENDPOINT': EVENT_GRID_ENDPOINT
    }
    
    for name, value in required_configs.items():
        if not value:
            raise ValueError(f"Missing required configuration: {name}")
    
    if not ALLOWED_CONTAINERS or ALLOWED_CONTAINERS == ['']:
        raise ValueError("ALLOWED_CONTAINERS must be configured")

def sanitize_filename(filename: str) -> str:
    """Sanitize filename to prevent path traversal and injection attacks"""
    if not filename:
        raise ValueError("Filename cannot be empty")
    
    # Remove path separators and null bytes
    filename = filename.replace('/', '').replace('\\', '').replace('\0', '')
    
    # Allow only alphanumeric, dots, hyphens, underscores
    if not re.match(r'^[a-zA-Z0-9._-]+$', filename):
        raise ValueError(f"Invalid filename format: {filename}")
    
    # Prevent directory traversal
    if '..' in filename:
        raise ValueError("Directory traversal detected in filename")
    
    return filename

def validate_container_name(container_name: str) -> str:
    """Validate container name against allowlist"""
    if not container_name:
        raise ValueError("Container name cannot be empty")
    
    # Sanitize container name
    container_name = container_name.strip().lower()
    
    # Check against allowlist
    if container_name not in [c.strip().lower() for c in ALLOWED_CONTAINERS]:
        raise ValueError(f"Container '{container_name}' not in allowlist")
    
    # Validate format (Azure blob container naming rules)
    if not re.match(r'^[a-z0-9]([a-z0-9-]{1,61}[a-z0-9])?$', container_name):
        raise ValueError(f"Invalid container name format: {container_name}")
    
    return container_name

def validate_file_extension(filename: str) -> bool:
    """Validate file extension against allowlist"""
    ext = os.path.splitext(filename)[1].lower()
    return ext in ALLOWED_FILE_EXTENSIONS

def validate_file_size(size_bytes: int) -> bool:
    """Validate file size is within limits"""
    max_bytes = MAX_FILE_SIZE_MB * 1024 * 1024
    return 0 < size_bytes <= max_bytes

def compute_content_hash(content: bytes) -> str:
    """Compute SHA-256 hash of content for integrity verification"""
    return hashlib.sha256(content).hexdigest()

def sanitize_for_logging(data: str, max_length: int = 100) -> str:
    """Sanitize data for safe logging - prevent log injection"""
    if not data:
        return ""
    
    # Remove newlines and control characters to prevent log injection
    sanitized = re.sub(r'[\r\n\t\x00-\x1f\x7f-\x9f]', '', str(data))
    
    # Truncate to prevent log flooding
    if len(sanitized) > max_length:
        sanitized = sanitized[:max_length] + "..."
    
    return sanitized

def process_file_content(content: bytes, filename: str) -> Dict[str, Any]:
    """Process file content securely"""
    try:
        # Validate content size
        if not validate_file_size(len(content)):
            raise ValueError(f"File size exceeds maximum allowed size of {MAX_FILE_SIZE_MB}MB")
        
        # Compute integrity hash
        content_hash = compute_content_hash(content)
        
        # Process based on file type
        ext = os.path.splitext(filename)[1].lower()
        
        processed_data = {
            'filename': filename,
            'size_bytes': len(content),
            'content_hash': content_hash,
            'processed_at': datetime.utcnow().isoformat(),
            'file_type': ext
        }
        
        # Safe content processing based on type
        if ext == '.json':
            try:
                # Limit JSON parsing to prevent DoS
                if len(content) > 1024 * 1024:  # 1MB limit for JSON
                    raise ValueError("JSON file too large for parsing")
                
                json_data = json.loads(content.decode('utf-8'))
                # Don't store raw content, only metadata
                processed_data['record_count'] = len(json_data) if isinstance(json_data, list) else 1
            except json.JSONDecodeError as e:
                processed_data['parse_error'] = 'Invalid JSON format'
        
        elif ext == '.txt':
            # Count lines without storing content
            line_count = content.decode('utf-8', errors='ignore').count('\n') + 1
            processed_data['line_count'] = line_count
        
        elif ext == '.csv':
            # Count rows without full parsing
            line_count = content.decode('utf-8', errors='ignore').count('\n')
            processed_data['row_count'] = line_count
        
        return processed_data
        
    except UnicodeDecodeError:
        raise ValueError("File encoding not supported")
    except Exception as e:
        logging.error(f"Error processing file: {sanitize_for_logging(str(e))}")
        raise

@app.blob_trigger(arg_name="myblob", path="samples-workitems/{name}",
                   connection="STORAGE_ACCOUNT_CONNECTION")
def blob_processor(myblob: func.InputStream):
    """
    Secure blob processor with input validation and least privilege access
    """
    try:
        # Validate configuration on startup
        validate_config()
        
        # Extract and validate blob metadata
        blob_name = myblob.name
        blob_path_parts = blob_name.split('/')
        
        if len(blob_path_parts) < 2:
            raise ValueError("Invalid blob path structure")
        
        container_name = blob_path_parts[0]
        filename = '/'.join(blob_path_parts[1:])
        
        # Validate container against allowlist
        container_name = validate_container_name(container_name)
        
        # Sanitize and validate filename
        filename_only = os.path.basename(filename)
        filename_only = sanitize_filename(filename_only)
        
        # Validate file extension
        if not validate_file_extension(filename_only):
            raise ValueError(f"File extension not allowed: {filename_only}")
        
        logging.info(f"Processing blob: container={sanitize_for_logging(container_name)}, "
                    f"file={sanitize_for_logging(filename_only)}")
        
        # Read blob content with size validation
        content = myblob.read()
        
        if not validate_file_size(len(content)):
            raise ValueError(f"File size {len(content)} bytes exceeds limit")
        
        # Process file content securely
        processed_data = process_file_content(content, filename_only)
        
        # Add metadata (no sensitive data)
        processed_data['id'] = compute_content_hash(f"{container_name}/{filename_only}/{datetime.utcnow().isoformat()}".encode())
        processed_data['container'] = container_name
        processed_data['status'] = 'processed'
        
        # Write to Cosmos DB using Managed Identity
        cosmos_client = CosmosClient(COSMOS_ENDPOINT, credential=credential)
        database = cosmos_client.get_database_client(COSMOS_DATABASE)
        container = database.get_container_client(COSMOS_CONTAINER)
        
        # Upsert document
        container.upsert_item(processed_data)
        
        logging.info(f"Successfully wrote to Cosmos DB: {processed_data['id']}")
        
        # Send notification via Event Grid using Managed Identity
        event_grid_client = EventGridPublisherClient(EVENT_GRID_ENDPOINT, credential=credential)
        
        # Create CloudEvent (no sensitive data in event)
        event = CloudEvent(
            type="BlobProcessing.Completed",
            source=f"/blobs/{container_name}",
            data={
                'filename': filename_only,
                'container': container_name,
                'size_bytes': processed_data['size_bytes'],
                'content_hash': processed_data['content_hash'],
                'processed_at': processed_data['processed_at'],
                'document_id': processed_data['id']
            },
            subject=f"blob/{container_name}/{filename_only}"
        )
        
        # Send event
        event_grid_client.send([event])
        
        logging.info(f"Successfully sent Event Grid notification for {filename_only}")
        
    except ValueError as ve:
        # Validation errors - log safely without sensitive data
        logging.error(f"Validation error: {sanitize_for_logging(str(ve))}")
        raise
    
    except Exception as e:
        # General errors - log safely
        logging.error(f"Error processing blob: {sanitize_for_logging(str(e))}")
        raise

